CREATE INDEX "idx_partners_logo_strip_full_proof" ON "partners" USING btree ("sort_order","name") WHERE "partners"."is_active" = true AND "partners"."is_published" = true AND "partners"."show_in_logo_strip" = true AND nullif(trim("partners"."logo_url"), '') IS NOT NULL AND "partners"."logo_usage_approved_at" IS NOT NULL AND nullif(trim("partners"."logo_usage_approved_by"), '') IS NOT NULL AND nullif(trim("partners"."logo_usage_scope"), '') IS NOT NULL;
